import { useEffect, useRef } from "react";

const About = () => {
  const sectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.querySelectorAll(".reveal").forEach((el, i) => {
              setTimeout(() => el.classList.add("revealed"), i * 120);
            });
          }
        });
      },
      { threshold: 0.15 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  const skills = [
    { label: "Responsive Web Design", icon: "⬡" },
    { label: "UI/UX Implementation", icon: "◈" },
    { label: "Social Media Strategy", icon: "◎" },
    { label: "Brand Development", icon: "◆" },
  ];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300;1,400&family=DM+Mono:wght@300;400;500&display=swap');

        .about-section {
          --ink: #0e0e0e;
          --paper: #f5f0e8;
          --accent: #c8553d;
          --accent-2: #2b5f4e;
          --muted: #7a7268;
          --border: rgba(14,14,14,0.12);
          font-family: 'DM Mono', monospace;
          background-color: var(--ink);
          position: relative;
          overflow: hidden;
          padding: 0;
        }

        /* Grain overlay */
        .about-section::before {
          content: '';
          position: absolute;
          inset: 0;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E");
          opacity: 0.35;
          pointer-events: none;
          z-index: 0;
        }

        .about-inner {
          position: relative;
          z-index: 1;
          display: grid;
          grid-template-columns: 1fr 1fr;
          min-height: 100vh;
        }

        /* LEFT COLUMN — photo + label stack */
        .about-left {
          position: relative;
          border-right: 1px solid rgba(255,255,255,0.08);
          display: flex;
          flex-direction: column;
        }

        .about-label-top {
          padding: 2.5rem 2.5rem 2rem;
          border-bottom: 1px solid rgba(255,255,255,0.08);
        }

        .about-label-top .eyebrow {
          font-family: 'DM Mono', monospace;
          font-size: 0.65rem;
          letter-spacing: 0.2em;
          text-transform: uppercase;
          color: var(--accent);
          margin-bottom: 0.4rem;
        }

        .about-label-top .index {
          font-family: 'DM Mono', monospace;
          font-size: 0.65rem;
          color: rgba(255,255,255,0.2);
        }

        .photo-wrapper {
          flex: 1;
          position: relative;
          overflow: hidden;
        }

        .photo-wrapper img {
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: top center;
          display: block;
          filter: sepia(15%) contrast(1.05);
          transition: transform 0.8s cubic-bezier(0.25, 0.46, 0.45, 0.94),
                      filter 0.8s ease;
        }

        .photo-wrapper:hover img {
          transform: scale(1.04);
          filter: sepia(0%) contrast(1.08);
        }

        /* Photo overlay tint */
        .photo-wrapper::after {
          content: '';
          position: absolute;
          inset: 0;
          background: linear-gradient(
            to top,
            rgba(14,14,14,0.6) 0%,
            transparent 40%
          );
          pointer-events: none;
        }

        .photo-badge {
          position: absolute;
          bottom: 2rem;
          left: 2rem;
          z-index: 2;
          display: flex;
          align-items: center;
          gap: 0.6rem;
          background: rgba(14,14,14,0.7);
          backdrop-filter: blur(12px);
          border: 1px solid rgba(255,255,255,0.1);
          border-radius: 2px;
          padding: 0.6rem 1rem;
        }

        .pulse-dot {
          width: 6px;
          height: 6px;
          background: #4ade80;
          border-radius: 50%;
          animation: pulse-ring 2s ease-in-out infinite;
          flex-shrink: 0;
        }

        @keyframes pulse-ring {
          0%, 100% { box-shadow: 0 0 0 0 rgba(74, 222, 128, 0.6); }
          50% { box-shadow: 0 0 0 5px rgba(74, 222, 128, 0); }
        }

        .photo-badge span {
          font-size: 0.65rem;
          letter-spacing: 0.12em;
          text-transform: uppercase;
          color: rgba(255,255,255,0.7);
        }

        /* RIGHT COLUMN — content */
        .about-right {
          display: flex;
          flex-direction: column;
          padding: 0;
        }

        .about-right-top {
          padding: 2.5rem 3rem 2.5rem;
          border-bottom: 1px solid rgba(255,255,255,0.08);
          flex-shrink: 0;
        }

        .about-right-top .section-number {
          font-size: 0.6rem;
          letter-spacing: 0.2em;
          color: rgba(255,255,255,0.2);
          text-transform: uppercase;
          margin-bottom: 3rem;
          display: block;
        }

        .headline-block {
          overflow: hidden;
        }

        .headline {
          font-family: 'Cormorant Garamond', serif;
          font-size: clamp(3rem, 5vw, 5rem);
          font-weight: 300;
          line-height: 0.95;
          color: #f5f0e8;
          letter-spacing: -0.02em;
          margin: 0;
        }

        .headline em {
          font-style: italic;
          color: var(--accent);
        }

        .about-body {
          padding: 2.5rem 3rem;
          flex: 1;
          display: flex;
          flex-direction: column;
          gap: 2rem;
          overflow-y: auto;
        }

        .body-text {
          font-size: 0.82rem;
          line-height: 1.85;
          color: rgba(245, 240, 232, 0.55);
          font-weight: 300;
          letter-spacing: 0.01em;
          margin: 0;
        }

        .body-text + .body-text {
          padding-top: 0;
        }

        .divider {
          width: 40px;
          height: 1px;
          background: var(--accent);
          opacity: 0.5;
        }

        .skills-block {
          margin-top: auto;
          padding-top: 1.5rem;
          border-top: 1px solid rgba(255,255,255,0.08);
        }

        .skills-label {
          font-size: 0.6rem;
          letter-spacing: 0.2em;
          text-transform: uppercase;
          color: rgba(255,255,255,0.25);
          margin-bottom: 1.2rem;
        }

        .skills-grid {
          display: grid;
          grid-template-columns: 1fr 1fr;
          gap: 0;
          border: 1px solid rgba(255,255,255,0.08);
        }

        .skill-item {
          display: flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0.9rem 1.1rem;
          border-right: 1px solid rgba(255,255,255,0.08);
          border-bottom: 1px solid rgba(255,255,255,0.08);
          cursor: default;
          transition: background 0.25s ease;
          position: relative;
          overflow: hidden;
        }

        .skill-item:nth-child(even) {
          border-right: none;
        }

        .skill-item:nth-child(3),
        .skill-item:nth-child(4) {
          border-bottom: none;
        }

        .skill-item::before {
          content: '';
          position: absolute;
          inset: 0;
          background: rgba(200, 85, 61, 0.06);
          transform: translateX(-100%);
          transition: transform 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94);
        }

        .skill-item:hover::before {
          transform: translateX(0);
        }

        .skill-item:hover .skill-icon {
          color: var(--accent);
        }

        .skill-icon {
          font-size: 0.75rem;
          color: rgba(255,255,255,0.2);
          transition: color 0.25s ease;
          flex-shrink: 0;
        }

        .skill-text {
          font-size: 0.68rem;
          letter-spacing: 0.05em;
          color: rgba(245, 240, 232, 0.65);
          text-transform: uppercase;
          font-weight: 400;
        }

        /* Reveal animation */
        .reveal {
          opacity: 0;
          transform: translateY(24px);
          transition: opacity 0.7s cubic-bezier(0.25, 0.46, 0.45, 0.94),
                      transform 0.7s cubic-bezier(0.25, 0.46, 0.45, 0.94);
        }

        .reveal.revealed {
          opacity: 1;
          transform: translateY(0);
        }

        /* Responsive */
        @media (max-width: 768px) {
          .about-inner {
            grid-template-columns: 1fr;
          }

          .about-left {
            border-right: none;
            border-bottom: 1px solid rgba(255,255,255,0.08);
          }

          .photo-wrapper {
            height: 60vw;
            flex: none;
          }

          .about-right-top {
            padding: 2rem;
          }

          .about-body {
            padding: 2rem;
          }

          .headline {
            font-size: clamp(2.5rem, 8vw, 4rem);
          }

          .skills-grid {
            grid-template-columns: 1fr;
          }

          .skill-item {
            border-right: none;
          }

          .skill-item:nth-child(3) {
            border-bottom: 1px solid rgba(255,255,255,0.08);
          }
        }
      `}</style>

      <section id="about" className="about-section" ref={sectionRef}>
        <div className="about-inner">

          {/* ── LEFT: Photo column ── */}
          <div className="about-left">
            <div className="about-label-top reveal">
              <p className="eyebrow">Portfolio</p>
              <span className="index">02 / About</span>
            </div>

            <div className="photo-wrapper">
              <img
                src="data:image/jpeg;base64,"
                alt="Promise Shedrack"
              />
              <div className="photo-badge reveal">
                <span className="pulse-dot" />
                <span>Available for work</span>
              </div>
            </div>
          </div>

          {/* ── RIGHT: Content column ── */}
          <div className="about-right">
            <div className="about-right-top">
              <span className="section-number reveal">[ Profile ]</span>
              <div className="headline-block reveal">
                <h2 className="headline">
                  Crafting the<br />
                  <em>web's visual</em><br />
                  language
                </h2>
              </div>
            </div>

            <div className="about-body">
              <p className="body-text reveal">
                I'm a dedicated remote front-end web designer with a passion for creating
                visually stunning and user-friendly websites. Working remotely allows me to
                collaborate with clients worldwide — bringing flexibility and deep focus
                to every project.
              </p>

              <div className="divider reveal" />

              <p className="body-text reveal">
                Beyond web design, I'm a skilled social media manager, helping brands
                build their online presence and connect with their audience through
                strategic content, consistent voice, and meaningful engagement.
              </p>

              <div className="skills-block reveal">
                <p className="skills-label">Disciplines</p>
                <div className="skills-grid">
                  {skills.map((skill, i) => (
                    <div className="skill-item" key={i}>
                      <span className="skill-icon">{skill.icon}</span>
                      <span className="skill-text">{skill.label}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>

        </div>
      </section>
    </>
  );
};

export default About;